import { Box, Button, Grid, TextField, Typography, Container, Stack, Divider, Paper } from '@mui/material';
import React, { useState } from 'react';
import LocalShippingIcon from '@mui/icons-material/LocalShipping';
import CheckCircleOutlineRoundedIcon from '@mui/icons-material/CheckCircleOutlineRounded';

const MyOrder = (props) => {
    const { order = [], promocode = "", promocodes = {} } = props;
    const [name, setName] = useState('');
    const [city, setCity] = useState('');
    const [postNumber, setPostnumber] = useState('');
    const [phone, setPhone] = useState('');
    const [email, setEmail] = useState('');
    const [coment, setComent] = useState('');
    const [isSubmitted, setIsSubmitted] = useState(false);

    const getDiscount = () => {
        if (promocode !== "") {
            for (const [promo, discount] of Object.entries(promocodes)) {
                if (promocode === promo) {
                    return discount / 100;
                }
            }
        }
        return 0;
    };

    const sumWithoutDisc = order.reduce((acc, item) => {
        return acc + item.price * item.quantity;
    }, 0);

    const discount = getDiscount();
    const sumWithDisc = parseInt(sumWithoutDisc * (1 - discount), 10);

    const send = async () => {
        const orderData = {
            customer: {
                name,
                city,
                postNumber,
                phone,
                email,
                comment: coment
            },
            items: order,
            totalWithoutPromo: sumWithoutDisc,
            appliedPromo: promocode,
            totalWithPromo: sumWithDisc
        };

        try {
            const response = await fetch('http://localhost:5000/api/orders', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(orderData),
            });

            if (response.ok) {
                setIsSubmitted(true);
                window.scrollTo(0, 0);
            } else {
                alert('Помилка при відправці замовлення.');
            }
        } catch (error) {
            console.error('Error sending order:', error);
            alert('Сталася помилка при з\'єднанні з сервером.');
        }
    };

    if (isSubmitted) {
        return (
            <Container maxWidth="sm" sx={{ py: 15, textAlign: 'center' }}>
                <CheckCircleOutlineRoundedIcon sx={{ fontSize: '5rem', color: 'primary.main', mb: 3 }} />
                <Typography variant="h3" sx={{ fontWeight: 800, mb: 2 }}>Order Confirmed</Typography>
                <Typography variant="body1" sx={{ color: 'text.secondary', mb: 4 }}>
                    Thank you for choosing Wear & Enjoy. We've received your order and will start processing it immediately.
                </Typography>
                <Button variant="contained" size="large" href="/">Back to Shop</Button>
            </Container>
        );
    }

    return (
        <Container maxWidth="lg" sx={{ py: 8 }}>
            <Typography variant="h2" sx={{ fontWeight: 800, mb: 1 }}>Checkout</Typography>
            <Typography variant="body1" sx={{ color: 'text.secondary', mb: 6 }}>
                Complete your order details below. Delivery is handled by Nova Poshta.
            </Typography>

            <Grid container spacing={6}>
                <Grid item xs={12} md={7}>
                    <Paper sx={{ p: 4, borderRadius: '24px', background: '#171A20' }}>
                        <Typography variant="h5" sx={{ fontWeight: 700, mb: 4, display: 'flex', alignItems: 'center', gap: 1.5 }}>
                            <LocalShippingIcon sx={{ color: 'primary.main' }} />
                            Shipping Information
                        </Typography>
                        
                        <Stack spacing={3}>
                            <TextField
                                fullWidth
                                label="Full Name"
                                required
                                variant="outlined"
                                value={name}
                                onChange={e => setName(e.target.value)}
                            />
                            
                            <Grid container spacing={2}>
                                <Grid item xs={8}>
                                    <TextField
                                        fullWidth
                                        label="City"
                                        required
                                        value={city}
                                        onChange={e => setCity(e.target.value)}
                                    />
                                </Grid>
                                <Grid item xs={4}>
                                    <TextField
                                        fullWidth
                                        label="Post Office №"
                                        required
                                        type="number"
                                        value={postNumber}
                                        onChange={e => setPostnumber(e.target.value)}
                                    />
                                </Grid>
                            </Grid>

                            <TextField
                                fullWidth
                                label="Phone Number"
                                required
                                type="tel"
                                value={phone}
                                onChange={e => setPhone(e.target.value)}
                            />

                            <TextField
                                fullWidth
                                label="Email"
                                type="email"
                                value={email}
                                onChange={e => setEmail(e.target.value)}
                            />

                            <TextField
                                fullWidth
                                label="Special Instructions (Optional)"
                                multiline
                                rows={3}
                                value={coment}
                                onChange={e => setComent(e.target.value)}
                            />
                        </Stack>
                    </Paper>
                </Grid>

                <Grid item xs={12} md={5}>
                    <Paper sx={{ p: 4, borderRadius: '24px', background: '#171A20', position: 'sticky', top: '120px' }}>
                        <Typography variant="h5" sx={{ fontWeight: 700, mb: 4 }}>Order Summary</Typography>
                        
                        <Stack spacing={2} sx={{ mb: 4 }}>
                            <Box sx={{ display: 'flex', justifyContent: 'space-between' }}>
                                <Typography sx={{ color: 'text.secondary' }}>Subtotal</Typography>
                                <Typography sx={{ fontWeight: 700 }}>{sumWithoutDisc} ₴</Typography>
                            </Box>
                            
                            {discount > 0 && (
                                <Box sx={{ display: 'flex', justifyContent: 'space-between' }}>
                                    <Typography sx={{ color: 'primary.main' }}>Discount ({promocode})</Typography>
                                    <Typography sx={{ color: 'primary.main', fontWeight: 700 }}>-{sumWithoutDisc - sumWithDisc} ₴</Typography>
                                </Box>
                            )}

                            <Box sx={{ display: 'flex', justifyContent: 'space-between' }}>
                                <Typography sx={{ color: 'text.secondary' }}>Shipping</Typography>
                                <Typography sx={{ fontWeight: 700 }}>Calculated at delivery</Typography>
                            </Box>
                            
                            <Divider sx={{ opacity: 0.1, my: 1 }} />
                            
                            <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'baseline' }}>
                                <Typography variant="h5" sx={{ fontWeight: 800 }}>Total</Typography>
                                <Typography variant="h4" sx={{ fontWeight: 800, color: 'primary.main' }}>{sumWithDisc} ₴</Typography>
                            </Box>
                        </Stack>

                        <Button 
                            fullWidth 
                            variant="contained" 
                            size="large" 
                            onClick={send}
                            sx={{ 
                                height: '64px', 
                                borderRadius: '16px', 
                                fontSize: '1.1rem', 
                                fontWeight: 700,
                                boxShadow: '0 8px 24px rgba(212, 175, 55, 0.25)'
                            }}
                        >
                            Place Order
                        </Button>
                        
                        <Typography variant="caption" sx={{ display: 'block', mt: 3, textAlign: 'center', color: 'text.secondary', px: 2 }}>
                            By placing an order, you agree to our Terms of Service and Privacy Policy.
                        </Typography>
                    </Paper>
                </Grid>
            </Grid>
        </Container>
    );
}

export default MyOrder;
